ORDER BY occurred_at ASC

SELECT * FROM dashboard_transcript_issue WHERE ( -- 条件1: turn_id 在指定列表中 AND occurred_at 在时间范围内 (turn_id IN
#{turnId}
AND occurred_at >= #{startTime} AND occurred_at <= #{endTime}) OR -- 条件2: occurred_at 在时间范围内但 turn_id 为 NULL (turn_id IS NULL AND occurred_at >= #{startTime} AND occurred_at <= #{endTime}) ) ORDER BY occurred_at ASC

